UPDATE public_catalog_import_items
SET status = 'FAILED',
    last_error = #{lastError}
WHERE id = #{itemId}

UPDATE public_catalog_import_jobs
SET status = 'FAILED',
    finished_at = CURRENT_TIMESTAMP,
    error_message = #{errorMessage}
WHERE id = #{jobId}
